arguments.keystrokes:
awk -F'\t' '
$2 != "/var/data" && $2 != "/var/data/logs" && $2 != "/var/data/backups" && $2 != "/var/data/cache" && $2 != "/var/data/cache/thumbnails" && $2 != "/var/data/uploads" && $2 != "/var/data/archives" {
  file = $2
  n = split(file, parts, "/")
  filename = parts[n]
  if (index(filename, ".") > 0) {
    m = split(filename, dots, ".")
    ext = tolower(dots[m])
  } else {
    ext = "NO_EXTENSION"
  }
  bytes[ext] += $1
}
END {
  for (ext in bytes) {
    print bytes[ext], ext
  }
}' /home/user/disk_inventory.txt | sort -k1,1nr | awk 'BEGIN {print "extension,total_bytes"} {print $2","$1}' > /home/user/reports/extension_summary.csv

awk -F'\t' '
BEGIN { total = 0 }
$2 ~ /^\/var\/data\/[^\/]+\// || ($2 ~ /^\/var\/data\/[^\/]+$/ && $2 != "/var/data/logs" && $2 != "/var/data/backups" && $2 != "/var/data/cache" && $2 != "/var/data/uploads" && $2 != "/var/data/archives") {
  path = $2
  sub(/^\/var\/data\//, "", path)
  n = split(path, parts, "/")
  subdir = parts[1]
  bytes[subdir] += $1
  total += $1
}
END {
  for (d in bytes) {
    pct = (bytes[d] / total) * 100
    printf "%s %d %.1f%%\n", d, bytes[d], pct
  }
}' /home/user/disk_inventory.txt | sort -t' ' -k2,2nr > /home/user/reports/directory_rollup.txt
